head.script:
/**
 * @event 
 * @name onpageload 
 * @description 화면 초기화
 */
scwin.onpageload = function () { };



/**
 * @event 
 * @name onUdcCompleted 
 * @description UDC 완료
 */
scwin.onUdcCompleted = function () {

    const codeOptions = [
        { grpCd: "FS262", compID: "acb_pchsAdmitClsCd" },
        { grpCd: "FS261", compID: "acb_copCoConfirmClsCd" },
    ];

    $c.data.setCommonCode(codeOptions, () => {
        acb_pchsAdmitClsCd.addItem('전체', '', '', 0);
        acb_copCoConfirmClsCd.addItem('전체', '', '', 0);
        acb_pchsAdmitClsCd.setSelectedIndex(0);
        acb_copCoConfirmClsCd.setSelectedIndex(0);
    });

};



/**
 * @event 
 * @name ondataload 
 * @description 코드 완료
 */
scwin.ondataload = function () {
    scwin.globalVars();
    scwin.f_OnLoad();
};




/**
 * @method 
 * @name globalVars 
 * @description 전역변수선언
 */
scwin.globalVars = function () {

    const loginDTO = $c.data.getMemInfo();  // 공통 세션 변수
    scwin.userClsCd = loginDTO.userClsCd;  // 사용자구분코드(02:협력업체(운송))
    scwin.loginClntNo = loginDTO.clntNo;
    scwin.loginClntNm = loginDTO.clntNm;

    scwin.vCurDate = $c.date.getServerDateTime('yyyyMMdd');  // 서버를 기준으로 현재 날짜 반환
    const yearMonth = scwin.vCurDate.slice(0, 6);

    scwin.vQryStDt = yearMonth + "01";  // 조회일자 from(현재 날짜가 포함된 달의 시작 일자)
    scwin.vQryEndDt = yearMonth + $c.date.getLastDateOfMonth(yearMonth);  // 조회일자 to(현재 날짜가 포함된 달의 마지막 일자)

};



/**
 * @method 
 * @name f_OnLoad 
 * @description 화면로딩시
 */
scwin.f_OnLoad = function () {

    acb_dtCls.setSelectedIndex(0);  // 일자구분
    scwin.f_SelWrkDt();
    scwin.f_SetDefaultData();
    $c.gus.cfDisableAllBtn();
    $c.gus.cfDisableObjects([ica_allCopCoConfirmDt]);

    // 테스트 데이터
    // ed_pchsClntNo.setValue('562133');
    // dma_wrkDt.set('from', '20090301');
    // dma_wrkDt.set('to', '20090306');

    // ed_pchsClntNo.setValue('223054');
    // dma_wrkDt.set('from', '20100103');
    // dma_wrkDt.set('to', '20100131');

};



/**
 * @method 
 * @name f_SetDefaultData 
 * @description Default Data Setting
 */
scwin.f_SetDefaultData = function () {

    scwin.f_GetConfirmCntTotAmt();  // 건수/총금액 계산
    dma_wrkDt.set('from', scwin.vQryStDt);  // 작업일자시작		
    dma_wrkDt.set('to', scwin.vQryEndDt);  // 작업일자종료
    dma_copCoConfirmDt.set('from', scwin.vQryStDt);  // 확인일자시작
    dma_copCoConfirmDt.set('to', scwin.vQryEndDt);  // 확인일자종료

    acb_pchsAdmitClsCd.setSelectedIndex(0);  // 동부승인구분
    acb_copCoConfirmClsCd.setSelectedIndex(0);  // 확인구분
    acb_wrkPlClsCd.setSelectedIndex(0);  // 작업장구분

    lay_gubun.hide(); // 작업장구분 전체시 작업장 조회 불가

    if (scwin.userClsCd != "01") {  // 내부사용자가 아니면
        ed_pchsClntNo.setValue(scwin.loginClntNo);
        txt_pchsClntNm.setValue(scwin.loginClntNm);
        ed_pchsClntNo.setDisabled(true);
        txt_pchsClntNm.setDisabled(true);
        img_PopUp1.setDisabled(true);
    } else {
        ed_pchsClntNo.focus();
    };

};



/**
 * @method 
 * @name f_RetrieveHeavyEquipLoanChargeList 
 * @description 중기임차료목록 조회
 */
scwin.f_RetrieveHeavyEquipLoanChargeList = async function () {

    // 검색조건 필수 입력 체크, 동일 날짜 포함 여부 체크
    if (acb_dtCls.getSelectedIndex() == 0) {  // 작업일자 기준			
        if (!await $c.gus.cfValidate([ed_pchsClntNo, ed_wrkDtSt, ed_wrkDtEnd])) {
            return;
        }

        if (!$c.gus.cfIsAfterDate(dma_wrkDt.get('from'), dma_wrkDt.get('to'))) {
            $c.gus.cfAlertMsg("조회 시작일자는 종료일자 보다 이전 날짜 이어야 합니다.");
            ed_wrkDtSt.focus();
            return;
        };

    } else if (acb_dtCls.getSelectedIndex() == 1) {  // 확인일자 기준
        if (!await $c.gus.cfValidate([ed_pchsClntNo, ed_copCoConfirmDtSt, ed_copCoConfirmDtEnd])) {
            return;
        }

        if (!$c.gus.cfIsAfterDate(dma_copCoConfirmDt.get('from'), dma_copCoConfirmDt.get('to'))) {
            $c.gus.cfAlertMsg("조회 시작일자는 종료일자 보다 이전 날짜 이어야 합니다.");
            ed_copCoConfirmDtSt.focus();
            return;
        };
    };

    // 구분(미확인포함여부/미승인포함여부)- 쿼리문에서 사용
    if (cbx_unconfirmedIncluYn.getValue() == 0 && cbx_unAdmitIncluYn.getValue() == 0) {
        dma_searchHeavyEquipLoanChargeList.set("incluYn", "N");
    } else {
        dma_searchHeavyEquipLoanChargeList.set("incluYn", "Y");
    };

    scwin.submitExcute(sbm_searchHeavyEquipLoanChargeList);

};



/**
 * @method 
 * @name f_Confirm 
 * @description 중기임차료 확인
 */
scwin.f_Confirm = function () {

    // Data 변경 여부 조회
    if (ds_heavyEquipLoanChargeList.getModifiedIndex().length == 0) {
        $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["자료"]);
        return;
    };

    // 협력업체확인구분(FS261)이 01:미확인, 03:이의신청, 04:이의거부, 05:이의수용
    let copCoConfirmClsCd = "", rowData = {};
    let rowCnt = ds_heavyEquipLoanChargeList.getRowCount();

    for (let i = 0; i < rowCnt; i++) {
        rowData = ds_heavyEquipLoanChargeList.getRowJSON(i);
        copCoConfirmClsCd = rowData.copCoConfirmClsCd;
        if (rowData.chk == "T") {
            if (copCoConfirmClsCd == "02") {
                $c.gus.cfAlertMsg("이미 확인된 건이 포함되어 있습니다.");
                return;
            };
        };
    };

    // 일괄적용 확인일자
    let allCopCoConfirmDt = ica_allCopCoConfirmDt.getValue();
    if ($c.gus.cfIsNull(allCopCoConfirmDt) || allCopCoConfirmDt == "") {
        allCopCoConfirmDt = scwin.vCurDate;
    };

    for (let i = 0; i < rowCnt; i++) {
        rowData = ds_heavyEquipLoanChargeList.getRowJSON(i);
        if (rowData.chk == "T") {
            rowData.copCoConfirmClsCd = "02";
            rowData.copCoConfirmClsNm = "확인";
            rowData.copCoConfirmDt = allCopCoConfirmDt;  // 일괄적용 확인일자
            rowData.btn = "T";
            rowData.chk = "F";

            ds_heavyEquipLoanChargeList.setRowJSON(i, rowData, true);
        };
    };

};



/**
 * @method 
 * @name f_ConfirmDtUpdate 
 * @description 중기임차료 확인일자 수정
 */
scwin.f_ConfirmDtUpdate = function () {

    // Data 변경 여부 조회
    if (ds_heavyEquipLoanChargeList.getModifiedIndex().length == 0) {
        $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["자료"]);
        return;
    };

    // 협력업체확인구분(FS261)이 02:확인 이면서 매입승인구분(FS262)이 01:미승인, 03:보류
    let copCoConfirmClsCd = "", pchsAdmitClsCd = "", rowData = {};
    let rowCnt = ds_heavyEquipLoanChargeList.getRowCount();

    for (let i = 0; i < rowCnt; i++) {
        rowData = ds_heavyEquipLoanChargeList.getRowJSON(i);
        copCoConfirmClsCd = rowData.copCoConfirmClsCd;
        pchsAdmitClsCd = rowData.pchsAdmitClsCd;

        if (rowData.chk == "T") {
            if (copCoConfirmClsCd != "02") {
                $c.gus.cfAlertMsg("미확인인 건이 포함되어 있습니다.");
                return;
            };
            if (pchsAdmitClsCd == "02") {
                $c.gus.cfAlertMsg("이미 동부 승인이 이루어진 건이 포함되어 있습니다.");
                return;
            };
        };
    };

    // 일괄적용 확인일자
    let allCopCoConfirmDt = ica_allCopCoConfirmDt.getValue();
    if ($c.gus.cfIsNull(allCopCoConfirmDt) || allCopCoConfirmDt == "") {
        allCopCoConfirmDt = scwin.vCurDate;
    };

    for (let i = 0; i < rowCnt; i++) {
        rowData = ds_heavyEquipLoanChargeList.getRowJSON(i);
        if (rowData.chk == "T") {
            rowData.copCoConfirmDt = allCopCoConfirmDt;  // 일괄적용 확인일자
            rowData.btn = "T";
            rowData.chk = "F";
            ds_heavyEquipLoanChargeList.setRowJSON(i, rowData, true);
        };
    };

};



/**
 * @method 
 * @name f_ConfirmDtUpdate 
 * @description 중기임차료 확인 취소
 */
scwin.f_ConfirmCancel = function () {

    // Data 변경 여부 조회
    if (ds_heavyEquipLoanChargeList.getModifiedIndex().length == 0) {
        $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["자료"]);
        return;
    };

    // 협력업체확인구분(FS261)이 02:확인 이면서 매입승인구분(FS262)이 01:미승인
    let copCoConfirmClsCd = "", pchsAdmitClsCd = "", rowData = {};
    let rowCnt = ds_heavyEquipLoanChargeList.getRowCount();

    for (let i = 0; i < rowCnt; i++) {
        rowData = ds_heavyEquipLoanChargeList.getRowJSON(i);
        copCoConfirmClsCd = rowData.copCoConfirmClsCd;
        pchsAdmitClsCd = rowData.pchsAdmitClsCd;

        if (rowData.chk == "T") {
            if (copCoConfirmClsCd != "02") {
                $c.gus.cfAlertMsg("미확인인 건이 포함되어 있습니다.");
                return;
            };
            if (pchsAdmitClsCd != "01") {
                $c.gus.cfAlertMsg("이미 동부 승인이 이루어진 건이 포함되어 있습니다.");
                return;
            };
        };
    };

    for (let i = 0; i < rowCnt; i++) {
        rowData = ds_heavyEquipLoanChargeList.getRowJSON(i);
        if (rowData.chk == "T") {
            rowData.copCoConfirmClsCd = "01";
            rowData.copCoConfirmClsNm = "미확인";
            rowData.copCoConfirmDt = "";
            rowData.rsltsPic = "";  // 실적담당자				
            rowData.btn = "T";
            rowData.chk = "F";
            ds_heavyEquipLoanChargeList.setRowJSON(i, rowData, true);
        };
    };

};



/**
 * @method 
 * @name f_ConfirmDtUpdate 
 * @description 중기임차료 이의제기
 */
scwin.f_DissentApply = function () {

    // Data 변경 여부 조회
    if (ds_heavyEquipLoanChargeList.getModifiedIndex().length == 0) {
        $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["자료"]);
        return;
    };

    // 협력업체확인구분(FS261)이 01:미확인, 04:이의거부, 05:이의수용
    let copCoConfirmClsCd = "", rowData = {};
    let rowCnt = ds_heavyEquipLoanChargeList.getRowCount();

    for (let i = 0; i < rowCnt; i++) {
        rowData = ds_heavyEquipLoanChargeList.getRowJSON(i);
        copCoConfirmClsCd = rowData.copCoConfirmClsCd;
        if (rowData.chk == "T") {
            if (["02", "03"].includes(copCoConfirmClsCd)) {
                $c.gus.cfAlertMsg("확인된 건이 포함되어 있습니다.\n해당건은 먼저 확인취소를 해야 합니다.");
                return;
            };
        };
    };

    for (let i = 0; i < rowCnt; i++) {
        rowData = ds_heavyEquipLoanChargeList.getRowJSON(i);
        if (rowData.chk == "T") {
            rowData.copCoConfirmClsCd = "03";
            rowData.copCoConfirmClsNm = "이의신청";
            rowData.copCoConfirmDt = "";
            rowData.dissent = "이의 내용을 입력하십시오.";
            rowData.btn = "T";
            rowData.chk = "F";
            ds_heavyEquipLoanChargeList.setRowJSON(i, rowData, true);
        };
    };

};



/**
 * @method 
 * @name f_Cancel 
 * @description 취소
 */
scwin.f_Cancel = function () {

    // Data 변경 여부 조회
    if (ds_heavyEquipLoanChargeList.getModifiedIndex().length == 0) {
        $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["자료"]);
        return;
    };

    // 취소할 목록 선택
    let cnt = 0;
    let rowCnt = ds_heavyEquipLoanChargeList.getRowCount();
    for (let i = 0; i < rowCnt; i++) {
        if (ds_heavyEquipLoanChargeList.getCellData(i, "chk") == "T") {
            cnt++;
        }
    };

    if (cnt == 0) {
        $c.gus.cfAlertMsg("취소할 목록을 선택하십시오.");
        return;
    }

    // 원래값 복원
    for (let i = 0; i < rowCnt; i++) {
        if (ds_heavyEquipLoanChargeList.getCellData(i, "chk") == "T") {
            ds_heavyEquipLoanChargeList.undoRow(i);  // 해당 DataSet의 Row를 원래값(=Original Data)로 복원
            ds_heavyEquipLoanChargeList.setCellData(i, "btn", "F");
            ds_heavyEquipLoanChargeList.setCellData(i, "chk", "F");
        };
    };

    gr_heavyEquipLoanChargeList.setColumnReadOnly('copCoConfirmDt', true);  // 입력불가

};



/**
 * @method 
 * @name f_Save 
 * @description 저장
 */
scwin.f_Save = async function () {

    // Data 변경 여부 조회
    if (ds_heavyEquipLoanChargeList.getModifiedIndex().length == 0) {
        $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["자료"]);
        return;
    };

    // 처리버튼 클릭여부
    let cnt = 0;
    let rowCnt = ds_heavyEquipLoanChargeList.getRowCount();

    for (let i = 0; i < rowCnt; i++) {
        if (ds_heavyEquipLoanChargeList.getCellData(i, "btn") == "T") {
            cnt++;
        };
    };

    if (cnt == 0) {
        $c.gus.cfAlertMsg("처리할 업무을 선택하십시오.");
        return;
    }

    // 확인 날짜입력시 validate 체크
    let copCoConfirmDt = "", copCoConfirmClsCd = "", dissent = "", rowData = {};
    for (let i = 0; i < rowCnt; i++) {
        rowData = ds_heavyEquipLoanChargeList.getRowJSON(i);
        copCoConfirmClsCd = rowData.copCoConfirmClsCd;

        if (rowData.btn == "T" && copCoConfirmClsCd == "02") {
            copCoConfirmDt = rowData.copCoConfirmDt;
            if ($c.num.isNumber(copCoConfirmDt)) {
                if (!$c.date.isDate(copCoConfirmDt, false)) {
                    $c.gus.cfAlertMsg((i + 1) + "번째 데이타에서 확인일자는 'YYYYMMDD' 형식이어야 합니다.");
                    ds_heavyEquipLoanChargeList.setRowPosition(i);
                    return;
                }
            }

            // 이의신청시 이의처리/보류사유 입력
            dissent = rowData.dissent;
            if (copCoConfirmClsCd == "03") {
                if (dissent.length == 0 || dissent == null || dissent == "이의 내용을 입력하십시오.") {
                    $c.gus.cfAlertMsg(i + "번째 데이타에서 이의처리/보류사유를 입력하십시오.");
                    ds_heavyEquipLoanChargeList.setRowPosition(i);
                    return;
                };
            };
        };
    };

    // 저장하시겠습니까?
    const retConfirm = await $c.win.confirm(MSG_CM_CRM_001);
    if (!retConfirm) return;
    scwin.submitExcute(sbm_saveHeavyEquipLoanChargeList);

};



/**
 * @method 
 * @name saveCallBack 
 * @description 이의신청 이력 수정
 * @param {number} row
 */
scwin.f_RetrieveDissentApplyHistory = function (row) {

    let rowData = ds_heavyEquipLoanChargeList.getRowJSON(row);

    // 팝업화면에게 key 정보인 오더번호와 매입순번을 넘겨준다.
    let data = {
        odrNo: rowData.odrNo,  // 오더번호
        pchsSeq: rowData.pchsSeq,  // 매입순번
    };

    let options = { type: 'browserPopup', width: '825px', height: '520px' };
    let url = '/ui/ds/fs/adjm/fs_102_01_01p.xml';

    // 이의신청 이력 화면 호출
    $c.win.openPopup(url, options, data);

    // 다시 조회함 
    scwin.f_RetrieveHeavyEquipLoanChargeList();

};



/**
 * @method 
 * @name saveCallBack 
 * @description 조회건수/조회총금액, 확인건수/확인총금액 계산
 */
scwin.f_GetConfirmCntTotAmt = function () {

    // 사용료 + 운반비
    let qryCnt = 0, qryTotAmt = 0;
    let rowCnt = ds_heavyEquipLoanChargeList.getRowCount();

    if (rowCnt > 0) {
        let colArray = [];
        colArray = ds_heavyEquipLoanChargeList.getColData('hveqLoanAmt');

        const hveqLoanAmt = colArray.reduce((accumulator, currentValue) => {
            return accumulator += $c.num.parseInt(currentValue);
        }, 0);


        colArray = ds_heavyEquipLoanChargeList.getColData('prtgCost');
        const prtgCost = colArray.reduce((accumulator, currentValue) => {
            return accumulator += $c.num.parseInt(currentValue);
        }, 0);

        qryCnt = rowCnt;
        qryTotAmt = hveqLoanAmt + prtgCost;
    };

    lay_qryCnt.setValue($c.gus.cfInsertComma(qryCnt));
    lay_qryTotAmt.setValue($c.gus.cfInsertComma(qryTotAmt));

    // 매입승인구분이 승인(02)인 경우만 사용료 + 운반비 계산
    let confirmCnt = 0, confirmTotAmt = 0;

    for (let i = 0; i < rowCnt; i++) {
        let rowData = ds_heavyEquipLoanChargeList.getRowJSON(i);
        if (rowData.copCoConfirmClsCd == "02") {
            confirmTotAmt += $c.num.parseInt(rowData.hveqLoanAmt) + $c.num.parseInt(rowData.prtgCost);
            confirmCnt++;
        };
    };

    lay_confirmCnt.setValue($c.gus.cfInsertComma(confirmCnt));
    lay_confirmTotAmt.setValue($c.gus.cfInsertComma(confirmTotAmt));

};



/**
 * @method 
 * @name f_SelWrkDt 
 * @description 작업일자 선택
 */
scwin.f_SelWrkDt = function () {
    udc_wrkDt.show('');
    udc_copCoConfirmDt.hide();
    lay_gubun1.show('');
    lay_gubun2.show('');
    lay_gubun3.show('');
    lay_gubun4.show('');
    lay_gubun5.show('');
};



/**
 * @method 
 * @name f_SelWrkDt 
 * @description 확인일자 선택
 */
scwin.f_SelCopCoConfirmDt = function () {
    udc_wrkDt.hide();
    udc_copCoConfirmDt.show('');
    lay_gubun1.hide();
    lay_gubun2.hide();
    lay_gubun3.hide();
    lay_gubun4.hide();
    lay_gubun5.hide();
};



/**
 * @method 
 * @name f_RunExcel 
 * @description 엑셀 다운로드
 */
scwin.f_RunExcel = function () {

    let count = ds_heavyEquipLoanChargeList.getRowCount();
    if (!(count > 0)) {
        $c.gus.cfAlertMsg(MSG_CM_WRN_002);  // 조회결과가 존재하지 않습니다.
        return;
    };

    let excelName = '중기임차료 내역 확인';

    let options = {
        sheetName: excelName,
        fileName: excelName + ".xlsx",
        startRowIndex: 2,
        useHeaderCheckBoxLabel: true
    };

    let infoArr = [{
        text: excelName,
        rowIndex: 0,
        colSpan: gr_heavyEquipLoanChargeList.getTotalCol(),
        textAlign: 'center',
        fontSize: '12px',
        fontName: '돋움체',
        color: 'black',
        bgColor: '#ffffff'
    }];

    $c.data.downloadGridViewExcel(gr_heavyEquipLoanChargeList, options, infoArr);

};




/**
 * @method 
 * @name f_openCommonPopUp 
 * @description 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
 * @param {number} disGubun
 * @param {string} pCode
 * @param {string} pName
 * @param {string} pClose
 * @param {string} pAllSearch
 */
scwin.f_openCommonPopUp = async function (disGubun, pCode, pName, pClose, pAllSearch) {

    let comCodeComp, codeNameArray, selectedId;
    let pDispCnt = null, pTitle = null, pWidth = null, pHidden = null,
        pWhere = null, pW = null, pH = null, pTop = null, pLeft = null,
        pExistTF = null, pWtitleSearch = null, pNoDataCloseTF = null;

    switch (disGubun) {
        case 1:
            // 협력회사 팝업
            comCodeComp = udc_pchsClnt;
            selectedId = 'retrieveClntList';
            codeNameArray = [ed_pchsClntNo, txt_pchsClntNm]; // 협력회사코드, 협력회사명	
            break;

        case 2:
            // 동부부서 팝업
            comCodeComp = udc_pchsDept;
            selectedId = 'retrieveLobranInfo';
            codeNameArray = [ed_pchsDeptCd, txt_pchsDeptNm];  // 점소코드, 점소명
            break;

        case 3:
            // 작업장 팝업
            comCodeComp = udc_wrkPl;
            selectedId = 'retrieveWrkPlInfo';
            codeNameArray = [ed_wrkPlCd, txt_wrkPlNm];  // 작업장코드, 작업장명		
            break;

        case 4:
            // 장비 팝업
            comCodeComp = udc_vehcl;
            selectedId = 'retrieveKndVehclListInfo';
            codeNameArray = [ed_vehclShortCd, txt_vehclNo];  // 차량번호, 차량단축코드

            pDispCnt = '2';
            pHidden = '3,4,5,6,7,8,9,10';
            pWhere = 'LO,LH';
            break;

        case 9:
            //본선관리번호
            let args = new Array();
            args[0] = ed_cvsslMgntNo.getValue(); //본선관리번호

            let url = '/ui/ds/op/wrkplan/stvwrkplan/op_204_01_07p.xml';
            let options = {
                type: 'browserPopup',
                width: '900px',
                height: '400px',
                popupName: '본선관리번호검색팝업',
            };

            let rtnValues = await $c.win.openPopup(url, options, args);

            if (rtnValues != null) ed_cvsslMgntNo.setValue(rtnValues[0]);
            break;

        case 10:
            // 협력업체 팝업			
            comCodeComp = udc_copCoClnt;
            selectedId = 'retrieveClntList';
            codeNameArray = [ed_copCoClntNo, txt_copCoClntNm];  // 협력회사코드, 협력회사명	
            break;

        default:
            break;
    };


    comCodeComp.setSelectId(selectedId);

    comCodeComp.cfCommonPopUp(
        (rtnList) => {
            $c.gus.cfSetReturnValue(rtnList, codeNameArray[0], codeNameArray[1]);
        },
        pCode.trim(),
        pName,
        pClose,
        pDispCnt,
        pTitle,
        pWidth,
        pHidden,
        pWhere,
        pW,
        pH,
        pTop,
        pLeft,
        pExistTF,
        pAllSearch,
        pWtitleSearch,
        pNoDataCloseTF
    );

};



/**
 * @method 
 * @name f_openCommonPopUp 
 * @description 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
 * @param {object} inObj
 * @param {object} pairObj
 * @param {number} disGubun
 * @param {string} isCode
 */
scwin.f_chkOpenCommonPopUp = function (inObj, pairObj, disGubun, isCode) {

    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj)) return;

    // 짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);

    // 검색어 세팅
    let pVal = inObj.getValue();

    // inObj가 코드 필드일 경우 팝업
    if (isCode == null || isCode == true)
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
    // inObj가 코드명 필드일 경우 팝업
    else
        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');

};



