/**
 * @event 
 * @name sbm_searchHeavyEquipLoanChargeList_submit 
 * @description 중기임차료목록 조회 요청전
 */
scwin.sbm_searchHeavyEquipLoanChargeList_submit = function (e) {

    let jsonData = dma_searchHeavyEquipLoanChargeList.getJSON();

    jsonData.pchsClntNo = ed_pchsClntNo.getValue(); // 협력회사 
    jsonData.pchsDeptCd = ed_pchsDeptCd.getValue(); // 동부부서 
    jsonData.wrkPlClsCd = acb_wrkPlClsCd.getValue(); // 작업장구분 
    jsonData.wrkPlCd = ed_wrkPlCd.getValue(); // 작업장 
    jsonData.vehclNo = txt_vehclNo.getValue(); // 장비
    jsonData.wrkDtSt = dma_wrkDt.get('from'); // 작업일자시작 
    jsonData.wrkDtEnd = dma_wrkDt.get('to'); // 작업일자종료 
    jsonData.dtCls = acb_dtCls.getValue(); // 일자구분(작업일자/확인일자) 
    jsonData.copCoConfirmDtSt = dma_copCoConfirmDt.get('from'); // 협력업체확인일자시작 
    jsonData.copCoConfirmDtEnd = dma_copCoConfirmDt.get('to'); // 협력업체확인일자종료 
    jsonData.pchsAdmitClsCd = acb_pchsAdmitClsCd.getValue(); // 협력업체확인구분코드 
    jsonData.copCoConfirmClsCd = acb_copCoConfirmClsCd.getValue(); // 매입승인구분코드 
    jsonData.unconfirmedIncluYn = cbx_unconfirmedIncluYn.getValue(); // 미확인포함여부 
    jsonData.unAdmitIncluYn = cbx_unAdmitIncluYn.getValue(); // 미승인포함여부 
    jsonData.copCoClntNoYn = cbx_copCoClntNoYn.getValue(); // 미승인포함여부 
    jsonData.cvsslMgntNo = ed_cvsslMgntNo.getValue(); // 본선관리번호 
    jsonData.copCoClntNo = ed_copCoClntNo.getValue(); // 협력업체 

    dma_searchHeavyEquipLoanChargeList.setJSON(jsonData);

};


/**
 * @event 
 * @name submitdone 
 * @description submit 정상
 */
scwin.submitdone = function (e) {

    let submitObj = $p.getComponentById(e.id);

    switch (submitObj) {
        case sbm_searchHeavyEquipLoanChargeList: // 중기임차료목록
            let rowCnt = ds_heavyEquipLoanChargeList.getRowCount();

            // 총 조회건수 표시
            totalRows.setValue(rowCnt);

            // 건수/총금액 계산
            scwin.f_GetConfirmCntTotAmt();

            gr_heavyEquipLoanChargeList.setHeaderValue('chkHeader', false);
            if (rowCnt == 0) {
                $c.gus.cfDisableAllBtn();
                $c.gus.cfDisableObjects([ica_allCopCoConfirmDt]);
                $c.gus.cfAlertMsg(MSG_CM_ERR_003);  // 해당되는 자료가 존재하지 않습니다
            } else {
                $c.gus.cfEnableAllBtn();
                $c.gus.cfEnableObjects([ica_allCopCoConfirmDt]);
            };
            break;

        case sbm_saveHeavyEquipLoanChargeList: // 중기임차료목록
            scwin.f_RetrieveHeavyEquipLoanChargeList();
            $c.gus.cfAlertMsg(MSG_CM_INF_001);	 // 성공적으로 저장하였습니다
            break;

        default:
            break;
    }

};







