 * @name acb_dtCls_onchange 
 * @description 조회조건(작업일자/확인일자) 선택
 */
scwin.acb_dtCls_onchange = function (info) {

    switch (acb_dtCls.getValue()) {
        case '01': scwin.f_SelWrkDt(); break;
        case '02': scwin.f_SelCopCoConfirmDt(); break;
        case '03': scwin.f_SelWrkDt(); break;
        default: break;
    };

};



/**
 * @event 
 * @name acb_wrkPlClsCd_onchange 
 * @description 작업장구분이 C:CY, F:CFS, E:장치장인 경우 작업장 조회 가능
 */
scwin.acb_wrkPlClsCd_onchange = function (info) {

    ed_wrkPlCd.setValue("");  // 작업장코드
    txt_wrkPlNm.setValue("");  // 작업장명		

    switch (acb_wrkPlClsCd.getValue()) {
        case 'C': case 'F': case 'E':
            lay_gubun.show('');
            break;

        case '': case 'P': case 'W':
            lay_gubun.hide()
            break;

        default:
            break;
    };

};



/**
 * @event 
 * @name gr_heavyEquipLoanChargeList_oneditend 
 * @description 셀의 편집이 끝난 경우 발생하며, onafteredit보다 먼저 발생
 * @param {number} rowIndex
 * @param {number} columnIndex
 * @param {string} value
 */
scwin.gr_heavyEquipLoanChargeList_oneditend = function (rowIndex, columnIndex, value) {

    // 확인 날짜입력시 validation 체크
    let colId = gr_heavyEquipLoanChargeList.getColumnID(columnIndex);
    switch (colId) {
        case 'copCoConfirmDt':
            let oldData = ds_heavyEquipLoanChargeList.getCellData(row, "copCoConfirmDt");
            if ($c.num.isNumber(value)) {
                if (!($c.date.isDate(value, false))) {
                    $c.gus.cfAlertMsg("확인일자는 'YYYYMMDD' 형식이어야 합니다.");
                    return;
                };
            } else {
                ds_heavyEquipLoanChargeList.setCellData(row, "copCoConfirmDt", oldData);
                $c.gus.cfAlertMsg("확인일자를 다시 입력하십시오.");
                return;
            };
            break;
        default:
            break;
    }

};



/**
 * @event 
 * @name gr_heavyEquipLoanChargeList_oncellclick 
 * @description 셀이 클릭된 경우 발생
 * @param {number} rowIndex
 * @param {number} columnIndex
 * @param {string} columnId
 */
scwin.gr_heavyEquipLoanChargeList_oncellclick = function (rowIndex, columnIndex, columnId) {

    let btn = ds_heavyEquipLoanChargeList.getCellData(rowIndex, "btn");
    let copCoConfirmClsCd = ds_heavyEquipLoanChargeList.getCellData(rowIndex, "copCoConfirmClsCd");

    // 확인
    switch (columnId) {
        case 'copCoConfirmDt':
            if (btn == "T" && copCoConfirmClsCd != "03") {
                gr_heavyEquipLoanChargeList.setColumnReadOnly('copCoConfirmDt', "Any");
            } else {
                gr_heavyEquipLoanChargeList.setColumnReadOnly('copCoConfirmDt', true);
            };

            // 미확인
            if (btn == "T" && copCoConfirmClsCd == "01") {
                gr_heavyEquipLoanChargeList.setColumnReadOnly('copCoConfirmDt', true);
            }
            break;

        case 'copCoConfirmDt':
            if (btn == "T" && copCoConfirmClsCd != "03") {
                gr_heavyEquipLoanChargeList.setColumnReadOnly('copCoConfirmDt', "Any");
            } else {
                gr_heavyEquipLoanChargeList.setColumnReadOnly('copCoConfirmDt', true);
            };

            // 이의처리/보류사유
            if (btn == "T" && copCoConfirmClsCd == "03") {
                gr_heavyEquipLoanChargeList.setColumnReadOnly('dissent', false);
            } else {
                gr_heavyEquipLoanChargeList.setColumnReadOnly('dissent', true);
            };

            // 이의처리/보류사유
            if (btn == "T" && copCoConfirmClsCd == "03") {
                gr_heavyEquipLoanChargeList.setColumnReadOnly('dissent', false);
            } else {
                gr_heavyEquipLoanChargeList.setColumnReadOnly('dissent', true);
            };

            // 이의신청 이력 수정
            if (ds_heavyEquipLoanChargeList.getRowStatusValue(rowIndex) == "0") {
                if (ds_heavyEquipLoanChargeList.getCellData(rowIndex, "dissent") != "") {
                    scwin.f_RetrieveDissentApplyHistory(rowIndex);
                };
            };
            break;

        default:
            break;
    };

};



